import React, { useState } from 'react';
import { fundApi } from '../../../services/api';

export default function AddExpensePage() {
  const [form, setForm] = useState({
    userCert: '',
    fundId: '',
    description: '',
    amount: '',
    spenderId: '',
  });
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState(null);

  const onChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const onSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);
    try {
      const { fundId, ...data } = form;
      const res = await fundApi.addExpense(fundId, data);
      setMessage(res?.data || 'Expense added successfully');
    } catch (err) {
      setMessage(err?.response?.data?.error || err.message || 'Failed to add expense');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={onSubmit} style={{ maxWidth: 800, margin: '0 auto' }}>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
        <div>
          <label>User Cert</label>
          <input
            name="userCert"
            value={form.userCert}
            onChange={onChange}
            placeholder="userCert"
            required
          />
        </div>

        <div>
          <label>Fund ID</label>
          <input
            name="fundId"
            value={form.fundId}
            onChange={onChange}
            placeholder="fundId"
            required
          />
        </div>

        <div>
          <label>Description</label>
          <input
            name="description"
            value={form.description}
            onChange={onChange}
            placeholder="description"
            required
          />
        </div>

        <div>
          <label>Amount</label>
          <input
            name="amount"
            value={form.amount}
            onChange={onChange}
            placeholder="amount"
            type="number"
            required
          />
        </div>

        <div>
          <label>Spender ID</label>
          <input
            name="spenderId"
            value={form.spenderId}
            onChange={onChange}
            placeholder="spenderId"
            required
          />
        </div>
      </div>

      <button type="submit" disabled={loading} style={{ marginTop: '12px', width: '100%' }}>
        {loading ? 'Sending...' : 'Send Request'}
      </button>

      {message && <div style={{ marginTop: 12 }}>{String(message)}</div>}
    </form>
  );
}
